import numpy as np
from typing import List, Dict, Tuple

class MultiStageWorkloadGenerator:
    def __init__(self, seed: int = 42):
        np.random.seed(seed)

    def generate_multistage_fanout_distribution(
        self,
        num_workflows_per_stage: List[int] = [100, 100, 100],
        fanouts: List[int] = [8, 15, 1]
    ) -> Dict[str, Dict]:
        """Generate stage-specific fanout distributions"""
        return {
            'stage_1': {
                'num_workflows': num_workflows_per_stage[0],
                'fanout': fanouts[0],
                'fanout_array': [fanouts[0]] * num_workflows_per_stage[0]
            },
            'stage_2': {
                'num_workflows': num_workflows_per_stage[1],
                'fanout': fanouts[1],
                'fanout_array': [fanouts[1]] * num_workflows_per_stage[1]
            },
            'stage_3': {
                'num_workflows': num_workflows_per_stage[2],
                'fanout': fanouts[2],
                'fanout_array': [fanouts[2]] * num_workflows_per_stage[2]
            }
        }

    def generate_bimodal_task_times(
        self,
        num_tasks: int,
        mode1: Tuple[float, float] = (5.0, 1.0),
        mode2: Tuple[float, float] = (10.0, 2.0),
        mix_ratio: float = 0.7
    ) -> np.ndarray:
        """Generate bimodal task execution times"""
        n_mode1 = int(num_tasks * mix_ratio)
        n_mode2 = num_tasks - n_mode1

        times_mode1 = np.random.normal(mode1[0], mode1[1], n_mode1)
        times_mode2 = np.random.normal(mode2[0], mode2[1], n_mode2)

        times = np.concatenate([times_mode1, times_mode2])
        np.random.shuffle(times)
        return np.clip(times, 1.0, None)  # Ensure positive times
