# redeployment_manager.py
import requests
import time
import logging
from typing import List, Dict, Tuple, Optional
from dataclasses import dataclass

@dataclass
class InstanceInfo:
    instance_id: str
    model_id: str
    scheduler_url: str
    port: int

@dataclass
class RedeploymentPlan:
    to_redeploy: List[InstanceInfo]
    new_scheduler_url: str
    total_changes: int

class RedeploymentManager:
    def __init__(self, scheduler_a_url: str, scheduler_b_url: str, base_instance_port: int = 9000):
        self.scheduler_a_url = scheduler_a_url
        self.scheduler_b_url = scheduler_b_url
        self.base_port = base_instance_port
        self.logger = logging.getLogger(__name__)

    def get_current_instance_allocation(self) -> Tuple[List[InstanceInfo], List[InstanceInfo]]:
        """Query schedulers for current instance registrations"""
        a_instances = []
        b_instances = []

        # Query Scheduler A
        resp = requests.get(f"{self.scheduler_a_url}/instances")
        for inst in resp.json().get('instances', []):
            a_instances.append(InstanceInfo(
                instance_id=inst['instance_id'],
                model_id=inst['model_id'],
                scheduler_url=self.scheduler_a_url,
                port=inst['port']
            ))

        # Query Scheduler B
        resp = requests.get(f"{self.scheduler_b_url}/instances")
        for inst in resp.json().get('instances', []):
            b_instances.append(InstanceInfo(
                instance_id=inst['instance_id'],
                model_id=inst['model_id'],
                scheduler_url=self.scheduler_b_url,
                port=inst['port']
            ))

        return a_instances, b_instances

    def plan_redeployment(
        self,
        current_a: List[InstanceInfo],
        current_b: List[InstanceInfo],
        target_a_count: int,
        target_b_count: int
    ) -> RedeploymentPlan:
        """Generate minimal change redeployment plan"""
        current_a_count = len(current_a)
        current_b_count = len(current_b)

        if target_a_count > current_a_count:
            # Need to move instances from B to A
            num_to_move = target_a_count - current_a_count
            to_redeploy = current_b[:num_to_move]
            new_scheduler = self.scheduler_a_url
        elif target_b_count > current_b_count:
            # Need to move instances from A to B
            num_to_move = target_b_count - current_b_count
            to_redeploy = current_a[:num_to_move]
            new_scheduler = self.scheduler_b_url
        else:
            # No changes needed
            to_redeploy = []
            new_scheduler = None

        return RedeploymentPlan(
            to_redeploy=to_redeploy,
            new_scheduler_url=new_scheduler,
            total_changes=len(to_redeploy)
        )

    def execute_redeployment(self, plan: RedeploymentPlan) -> bool:
        """Execute redeployment plan with retries and status checking"""
        if not plan.to_redeploy:
            self.logger.info("No redeployment needed")
            return True

        self.logger.info(f"Redeploying {plan.total_changes} instances")

        for instance in plan.to_redeploy:
            success = self._redeploy_instance(instance, plan.new_scheduler_url)
            if not success:
                self.logger.error(f"Failed to redeploy {instance.instance_id}")
                return False

        return True

    def _redeploy_instance(self, instance: InstanceInfo, new_scheduler_url: str, max_retries: int = 3) -> bool:
        """Redeploy single instance with retries"""
        instance_url = f"http://localhost:{instance.port}"

        for attempt in range(max_retries):
            try:
                # Call restart API
                resp = requests.post(
                    f"{instance_url}/model/restart",
                    json={
                        "model_id": "sleep_model",
                        "scheduler_url": new_scheduler_url
                    },
                    timeout=10
                )

                if resp.status_code != 200:
                    continue

                operation_id = resp.json()['operation_id']

                # Poll for completion
                if self._wait_for_restart(instance_url, operation_id):
                    return True

            except Exception as e:
                self.logger.warning(f"Attempt {attempt+1} failed: {e}")

        return False

    def _wait_for_restart(self, instance_url: str, operation_id: str, timeout: int = 120) -> bool:
        """Poll restart status until completion"""
        start_time = time.time()

        while time.time() - start_time < timeout:
            try:
                resp = requests.get(
                    f"{instance_url}/model/restart/status",
                    params={'operation_id': operation_id}
                )

                status = resp.json()['status']

                if status == 'completed':
                    return True
                elif status == 'failed':
                    return False

                time.sleep(2)

            except Exception:
                pass

        return False
